const mongoose = require('mongoose');
const axios = require('axios');
require('dotenv').config();

const API_URL = 'http://localhost:5003';

const COLORS = {
    RESET: '\x1b[0m',
    GREEN: '\x1b[32m',
    RED: '\x1b[31m',
    YELLOW: '\x1b[33m',
    CYAN: '\x1b[36m'
};

function log(msg, color = COLORS.RESET) {
    console.log(`${color}${msg}${COLORS.RESET}`);
}

const getHeaders = (cookie) => ({
    headers: {
        'Cookie': cookie,
        'Content-Type': 'application/json'
    },
    withCredentials: true
});

async function runAudit() {
    log('=== STARTING SYSTEM AUDIT ===', COLORS.CYAN);

    try {
        const mongoUri = 'mongodb://127.0.0.1:27017/saveserve';
        log(`Connecting to MongoDB at ${mongoUri}...`);
        await mongoose.connect(mongoUri, { serverSelectionTimeoutMS: 5000 });
        log('✓ MongoDB Connected', COLORS.GREEN);

        log(`Connection State: ${mongoose.connection.readyState}`);

        // Use Native Driver for Setup Queries to avoid Model/Schema issues
        const db = mongoose.connection.db;

        // 1. SETUP & CLEANUP
        log('\n--- PHASE 1: SETUP ---', COLORS.YELLOW);

        // Find Owner & Student
        log('Finding Owner (Native)...');
        const ownerUser = await db.collection('users').findOne({ role: 'owner' });
        log(`Found Owner: ${ownerUser ? ownerUser.email : 'None'}`);

        log('Finding Student (Native)...');
        const studentUser = await db.collection('users').findOne({ role: 'student' });
        log(`Found Student: ${studentUser ? studentUser.email : 'None'}`);

        if (!ownerUser || !studentUser) throw new Error('Owner or Student not found in DB');

        // Authenticate Owner
        let ownerCookie;
        try {
            const res = await axios.post(`${API_URL}/api/auth/login`, {
                email: 'owner@saveserve.com',
                password: '123456'
            });
            ownerCookie = res.headers['set-cookie'][0];
            log('✓ Owner Authenticated', COLORS.GREEN);
        } catch (e) {
            throw new Error('Owner Login Failed: ' + (e.response?.data?.msg || e.message));
        }

        // Authenticate Student
        let studentCookie;
        try {
            const res = await axios.post(`${API_URL}/api/auth/login`, {
                email: 'student@saveserve.com',
                password: '123456'
            });
            studentCookie = res.headers['set-cookie'][0];
            log('✓ Student Authenticated', COLORS.GREEN);
        } catch (e) {
            throw new Error('Student Login Failed: ' + (e.response?.data?.msg || e.message));
        }

        // Cleanup Timestamps
        const tomorrow = new Date();
        tomorrow.setDate(tomorrow.getDate() + 1);
        const tDateStr = tomorrow.toISOString().split('T')[0];

        const startOfDay = new Date(`${tDateStr}T00:00:00.000Z`);
        const endOfDay = new Date(`${tDateStr}T23:59:59.999Z`);

        // Cleanup MealBookings strict date range
        await db.collection('mealbookings').deleteMany({
            date: { $gte: startOfDay, $lte: endOfDay }
        });
        log('✓ Cleaned Test Data (MealBookings)', COLORS.GREEN);

        // 2. MENU CREATION
        log('\n--- PHASE 2: MENU CREATION ---', COLORS.YELLOW);

        // Create/Find Dish (Native)
        let dish = await db.collection('fooditems').findOne({ foodName: 'Audit Dish' });
        if (!dish) {
            const newDish = {
                foodName: 'Audit Dish',
                category: 'Breakfast',
                vegOrNonVeg: 'veg', // Lowercase as per validation often? Or Enum?
                price: 50,
                maxQuantity: 2,
                ownerId: ownerUser._id,
                __v: 0
            };
            const result = await db.collection('fooditems').insertOne(newDish);
            dish = { ...newDish, _id: result.insertedId };
        }
        log(`✓ Test Dish Ready: ${dish.foodName} (Max: ${dish.maxQuantity})`, COLORS.GREEN);

        // Publish Menu using API
        await axios.post(`${API_URL}/api/owner/save-menu`, {
            date: tDateStr,
            mealType: 'breakfast',
            vegItems: [{
                _id: dish._id.toString(),
                foodName: dish.foodName,
                quantity: 1,
                maxQuantity: 2
            }],
            nonVegItems: [],
            status: 'PUBLISHED'
        }, getHeaders(ownerCookie));
        log('✓ Menu Published for Tomorrow', COLORS.GREEN);

        // FETCH Menu to get ITEM ID
        const menuRes = await axios.get(`${API_URL}/api/owner/menu?date=${tDateStr}&mealType=breakfast`, getHeaders(ownerCookie));
        const menuItem = menuRes.data.vegItems.find(i => i.foodName === 'Audit Dish');
        if (!menuItem) throw new Error('Failed to retrieve created menu item ID');
        const validDishId = menuItem._id;


        // 3. BOOKING LOGIC VALIDATION
        log('\n--- PHASE 3: BOOKING LOGIC ---', COLORS.YELLOW);

        // Test A: Normal Booking
        await axios.post(`${API_URL}/api/student/select`, {
            date: tDateStr,
            mealType: 'breakfast',
            items: [{ _id: validDishId, itemName: dish.foodName, quantity: 2 }]
        }, getHeaders(studentCookie));
        log('✓ PASS: Normal Booking (Qty 2)', COLORS.GREEN);

        // Test B: Over-Limit Booking
        try {
            await axios.post(`${API_URL}/api/student/select`, {
                date: tDateStr,
                mealType: 'breakfast',
                items: [{ _id: validDishId, itemName: dish.foodName, quantity: 3 }]
            }, getHeaders(studentCookie));
            log('✗ FAIL: Over-limit booking was allowed!', COLORS.RED);
        } catch (e) {
            if (e.response && e.response.status === 400) {
                log('✓ PASS: Over-limit Booking Rejected', COLORS.GREEN);
            } else {
                log(`✗ FAIL: Unexpected error on over-limit: ${e.message}`, COLORS.RED);
            }
        }

        // Test C: Past Date Booking
        const yesterday = new Date();
        yesterday.setDate(yesterday.getDate() - 1);
        const yDateStr = yesterday.toISOString().split('T')[0];
        try {
            await axios.post(`${API_URL}/api/student/select`, {
                date: yDateStr,
                mealType: 'breakfast',
                items: [{ _id: validDishId, itemName: dish.foodName, quantity: 1 }]
            }, getHeaders(studentCookie));
            log('✗ FAIL: Past date booking was allowed!', COLORS.RED);
        } catch (e) {
            if (e.response && e.response.status === 400) {
                log('✓ PASS: Past Date Booking Rejected', COLORS.GREEN);
            } else {
                log(`✗ FAIL: Unexpected error on past date: ${e.message}`, COLORS.RED);
            }
        }

        // Test D: Duplicate/Upsert (Updates existing booking)
        await axios.post(`${API_URL}/api/student/select`, {
            date: tDateStr,
            mealType: 'breakfast',
            items: [{ _id: validDishId, itemName: dish.foodName, quantity: 1 }]
        }, getHeaders(studentCookie));
        log('✓ PASS: Booking Update (Qty changed to 1)', COLORS.GREEN);

        // Test E: Verify GET /booking Endpoint
        const bookingRes = await axios.get(`${API_URL}/api/student/booking?date=${tDateStr}&mealType=breakfast`, getHeaders(studentCookie));
        if (bookingRes.data.booked && bookingRes.data.booking.items[0].quantity === 1) {
            log('✓ PASS: GET /booking returned correct data', COLORS.GREEN);
        } else {
            log('✗ FAIL: GET /booking failed or returned incorrect data', COLORS.RED);
            console.log(bookingRes.data);
        }

        // 4. AGGREGATION VERIFICATION
        log('\n--- PHASE 4: AGGREGATION ---', COLORS.YELLOW);

        const res = await axios.get(`${API_URL}/api/owner/preparation-summary?date=${tDateStr}`, getHeaders(ownerCookie));
        const data = res.data;

        log('Received Aggregation Data:', COLORS.CYAN);
        console.log(JSON.stringify(data, null, 2));

        const breakfastItems = data.breakfast || [];
        const targetItem = breakfastItems.find(i => i.item === 'Audit Dish');

        if (!targetItem) {
            console.log('Available Items:', JSON.stringify(breakfastItems));
            log('✗ FAIL: Item not found in aggregation summary', COLORS.RED);
            process.exit(1);
        } else if (targetItem.quantity === 1) {
            log('✓ PASS: Quantity Matches (Expected 1)', COLORS.GREEN);
        } else {
            log(`✗ FAIL: Quantity Mismatch. Expected 1, Got ${targetItem.quantity}`, COLORS.RED);
            process.exit(1);
        }

        log('\n=== AUDIT COMPLETE ===', COLORS.CYAN);
        process.exit(0);

    } catch (err) {
        log(`\nFATAL ERROR: ${err.message}`, COLORS.RED);
        if (err.response) {
            console.log('Response Data:', err.response.data);
        }
        process.exit(1);
    }
}

runAudit();

const mongoose = require('mongoose');
const MealBooking = require('./server/models/MealBooking');
const dotenv = require('dotenv');
dotenv.config();

const MONGO_URI = process.env.MONGODB_URI || 'mongodb://0.0.0.0:27017/saveserve';
console.log("Connecting to:", MONGO_URI);

mongoose.connect(MONGO_URI)
    .then(async () => {
        console.log('Connected to MongoDB');
        try {
            const bookings = await MealBooking.find({});
            console.log('Found Bookings:', bookings.length);
            console.log(JSON.stringify(bookings, null, 2));
        } catch (e) {
            console.error(e);
        } finally {
            mongoose.connection.close();
        }
    })
    .catch(err => console.error(err));

const axios = require('axios');

const API_URL = 'http://localhost:5003'; // Updated to match server port

// Credentials from seed.js
const OWNER_CREDS = { email: 'owner@saveserve.com', password: '123456' };
const STUDENT_CREDS = { email: 'student@saveserve.com', password: '123456' };

// Helper to get headers
const getHeaders = (cookie) => ({
    headers: {
        'Cookie': cookie,
        'Content-Type': 'application/json'
    }
});

// Helper to get tomorrow's date YYYY-MM-DD
const getTomorrow = () => {
    const d = new Date();
    d.setDate(d.getDate() + 1);
    const y = d.getFullYear();
    const m = String(d.getMonth() + 1).padStart(2, '0');
    const day = String(d.getDate()).padStart(2, '0');
    return `${y}-${m}-${day}`;
};

const tomorrow = getTomorrow();

async function runVerification() {
    console.log("=== Starting System Verification ===");
    console.log(`Target Date: ${tomorrow}`);

    try {
        // 1. OWNER LOGIN
        console.log("\n1. Logging in Owner...");
        const ownerRes = await axios.post(`${API_URL}/api/auth/login`, OWNER_CREDS);
        const ownerCookie = ownerRes.headers['set-cookie'][0];
        console.log("   Owner Logged In.");

        // 1b. CHECK DASHBOARD (Sanity Check)
        console.log("\n1b. Checking Dashboard...");
        try {
            await axios.get(`${API_URL}/api/owner/dashboard`, getHeaders(ownerCookie));
            console.log("   Dashboard OK.");
        } catch (e) {
            console.log("   Dashboard Failed:", e.message);
        }

        // 2. CHECK/CREATE MENU FOR TOMORROW (Breakfast)
        console.log("\n2. Getting Existing Dishes...");
        let testDish = null;
        try {
            const dishesRes = await axios.get(`${API_URL}/api/owner/dishes`, getHeaders(ownerCookie));
            const dishes = dishesRes.data.dishes || dishesRes.data; // Handle pagination structure or plain array
            if (dishes.length > 0) {
                testDish = dishes[0];
                console.log(`   Using Existing Dish: ${testDish.foodName}`);
            }
        } catch (e) {
            console.log("   Could not fetch dishes, using fallback item.");
        }

        if (!testDish) {
            console.log("   Using Fallback Dummy Dish...");
            testDish = {
                foodName: "Verification Poha",
                imageUrl: "/menu-images/placeholder.jpg",
                vegOrNonVeg: "veg",
                price: 20
            };
        }

        console.log("   Publishing Menu for Tomorrow...");
        const menuPayload = {
            date: tomorrow,
            mealType: 'breakfast',
            vegItems: [{ ...testDish, maxQuantity: 2 }], // Set max quantity to 2
            nonVegItems: [],
            status: 'PUBLISHED'
        };

        try {
            await axios.post(`${API_URL}/api/owner/save-menu`, menuPayload, getHeaders(ownerCookie));
            console.log("   Menu Published.");
        } catch (e) {
            console.log("   Menu save error (might be duplicate/update):", e.response?.data?.msg || e.message);
        }

        // 2b. FETCH MENU TO GET ACTUAL ID
        console.log("   Fetching Saved Menu to get valid Item ID...");
        const menuRes = await axios.get(`${API_URL}/api/owner/menu?date=${tomorrow}&mealType=breakfast`, getHeaders(ownerCookie));
        const savedMenu = menuRes.data;
        const savedItem = savedMenu.vegItems.find(i => i.foodName === testDish.foodName);

        if (!savedItem) throw new Error("Saved item not found in fetched menu!");
        const validDishId = savedItem._id;
        console.log(`   Got Valid Item ID: ${validDishId}`);

        // 3. STUDENT LOGIN
        console.log("\n3. Logging in Student...");
        const studentRes = await axios.post(`${API_URL}/api/auth/login`, STUDENT_CREDS);
        const studentCookie = studentRes.headers['set-cookie'][0];
        console.log("   Student Logged In.");

        // 4. STUDENT ATTEMPT BOOKING (Valid Quantity)
        console.log("\n4. Student Booking Item (Qty: 2)...");
        const bookingPayloadValid = {
            date: tomorrow,
            mealType: 'breakfast',
            items: [
                { _id: validDishId, quantity: 2, itemName: testDish.foodName }
            ]
        };
        await axios.post(`${API_URL}/api/student/select`, bookingPayloadValid, getHeaders(studentCookie));
        console.log("   Booking Successful (Qty 2).");

        // 5. ATTEMPT BOOKING (Invalid Quantity - Exceeds Max)
        console.log("\n5. Student Attempting Over-limit Booking (Qty: 3)...");
        const bookingPayloadInvalid = {
            date: tomorrow,
            mealType: 'breakfast',
            items: [
                { _id: validDishId, quantity: 3, itemName: testDish.foodName }
            ]
        };
        try {
            await axios.post(`${API_URL}/api/student/select`, bookingPayloadInvalid, getHeaders(studentCookie));
            console.error("   FAILED: Should have rejected booking > max limit.");
        } catch (err) {
            console.log(`   Correctly Rejected: ${err.response?.data?.msg || err.message}`);
        }

        // 6. OWNER PREPARATION SUMMARY
        console.log("\n6. Owner Checking Preparation Summary...");
        const prepRes = await axios.get(`${API_URL}/api/owner/preparation-summary?date=${tomorrow}`, getHeaders(ownerCookie));
        const prepData = prepRes.data;

        console.log("   Preparation Data:", JSON.stringify(prepData, null, 2));

        const breakfastItems = prepData.breakfast || [];
        const foundItem = breakfastItems.find(i => i.item === testDish.foodName);

        if (foundItem && foundItem.quantity === 2) {
            console.log("\nSUCCESS: Verification Complete! Quantity matches.");
        } else {
            console.error("\nFAILURE: Quantity mismatch or item not found in summary.");
            console.error("Expected 2, Found:", foundItem ? foundItem.quantity : "Not Found");
        }

    } catch (err) {
        console.error("\nERROR:", err.message);
        if (err.response) {
            console.error("Response Data:", err.response.data);
        }
    }
}

runVerification();
